update payment_wallet
account_id = #{accountId,jdbcType=BIGINT}, balance = #{balance,jdbcType=BIGINT}, version = #{version,jdbcType=INTEGER}, gmt_create = #{gmtCreate,jdbcType=TIMESTAMP}, gmt_modified = #{gmtModified,jdbcType=TIMESTAMP},
