update payment_wallet
set balance = balance - #{amount,jdbcType=BIGINT},
    version = version + 1,
    gmt_modified = NOW()
where id = #{walletId,jdbcType=BIGINT}
  and version = #{version,jdbcType=INTEGER}
  and balance >= #{amount,jdbcType=BIGINT}
